643:     // format which uses an object for configuration
644:     if (oldVersion < 38 && finalTargetVersion >= 38) {
645:       panelUpgrades.push((panel: PanelModel) => {
646:         if (panel.type === 'table' && panel.fieldConfig !== undefined) {
647:           const displayMode = panel.fieldConfig.defaults?.custom?.displayMode;
648: 
649:           // Update field configuration
650:           if (displayMode !== undefined) {
651:             // Migrate any options for the panel
652:             panel.fieldConfig.defaults.custom.cellOptions = migrateTableDisplayModeToCellOptions(displayMode);
653: 
654:             // Delete the legacy field
655:             delete panel.fieldConfig.defaults.custom.displayMode;
656:           }
657: 
